void emit_instr2(char *op, char *arg1, char *arg2) {
    emit_str(EMIT_INDENT);
    emit_str(op);
    emit_str("     ");
    emit_str(arg1);
    emit_char(44);  /* ',' */
    emit_str(arg2);
    emit_nl();
}

/* Emit a raw instruction line (already formatted) */
void emit_instr(char *line) {
    emit_str(EMIT_INDENT);
    emit_line(line);
}

/* --- Comment emission --- */

/* Emit a comment line (e.g., "; PL/SW: x = y + 1;") */
void emit_comment(char *text) {
