    emit_str("; ");
    emit_line(text);
}

/* Emit a source-line tracking comment */
void emit_source_line(char *source) {
    emit_comment(source);
}

/* --- Data emission helpers --- */

/* Emit a .byte directive */
void emit_byte(int val) {
