}

/* --- Procedure helpers --- */

/* Emit standard COR24 procedure prologue */
void emit_prologue(void) {
    emit_instr1("push", "fp");
    emit_instr1("push", "r2");
    emit_instr1("push", "r1");
    emit_instr2("mov", "fp", "sp");
}

