}

/* --- Output access --- */

/* Null-terminate the buffer and return pointer */
char *emit_output(void) {
    if (emit_pos < EMIT_BUF_SIZE) {
        emit_buf[emit_pos] = 0;
    }
    return emit_buf;
}

/* Return current output length */
int emit_length(void) {
    return emit_pos;
}

#endif /* EMIT_H */

