    int result = type_binop_result(op, lt, rt);
    uart_putstr(" => ");
    uart_putstr(nd_type_name(result));
    if (result == expect) {
        uart_puts(" OK");
    } else {
        uart_putstr(" FAIL(expected ");
        uart_putstr(nd_type_name(expect));
        uart_puts(")");
    }
}

void test_types(void) {
