    /* Test 8: mixed param types (BYTE, PTR, INT24) */
    uart_puts("--- mixed params ---");
    arena_init();
    ast_init();
    sym_init();
    types_init();
    layout_init();

    parse_init("PROC FILL(DST PTR, VAL BYTE, LEN INT(24)); RETURN; END;");
    proc = parse_proc();
    if (!parse_err && proc != NODE_NULL) {
        fsize = layout_proc(proc);

        idx = sym_lookup("DST");
