        idx = sym_lookup("LIMIT");
        uart_putstr("  LIMIT(global): offset=");
        print_int(sym_offset[idx]);
        uart_putchar(10);

        /* Now lay out the proc */
        int child = nd_left[prog];
        while (child != NODE_NULL) {
            if (nd_kind[child] == NODE_PROC) {
                fsize = layout_proc(child);
